  ('Pablo Avaria', 'Executive Board Member', 'Harvard PLD 2025 | Board Member · Pablo Avaria is a globally focused business strategist with an MBA from Monash University and the Program for Leadership Development (Harvards Executive MBA Alternative) at Harvard Business School. His academic pathway has been intentionally designed to prepare for high-impact consulting in marketing, growth, and corporate strategy.At Harvard, Pablo is trained in the case method used by top global firms developing decision-making, leadership, and strategic problem-solving skills under the guidan', 'The Rocks, New South Wales, Australia', 'Senior operator with extensive ANZ market experience.', ARRAY['Active Advisor', 'Trade & Government'], 'https://linkedin.com/in/pablo-avaria', NULL, NULL, 'Professionals in International Trade (PIT)', FALSE, '[{"name": "Professionals in International Trade (PIT)"}, {"name": "Israel Trade and Economic Commission Australia"}]'::jsonb, 'usa', ARRAY['usa', 'australia'], NULL, 'pablo-avaria', 'Active Advisor', ARRAY['international_entrant'], TRUE, FALSE),
  ('Nagender Chetti', 'Founder', 'Fractional Executive | Founder @ Neura Vision | Data, Analytics & AI Strategy | Generative AI & Digital Transformation Leader | Driving Business Growth & Innovation | Top 25 Analytics Leader (IAPA 2023)| · Recognised as one of Australia’s Top 25 Analytics Leaders (IAPA 2023), I am a strategic and impact-focused executive with over 20 years experience at the intersection of data, analytics, AI, digital transformation, and business strategy. I help forward-thinking organisations unlock growth, accelerate innovation, and embed future-ready capabilities across insurance, financial services, and technology.With deep expertise in data strategy, analytics, AI adoption, digital innovation, business transf', 'Greater Melbourne Area', '20+ years operating experience in ANZ and international markets.', ARRAY['International Founder', 'Market Research / Strategy'], 'https://linkedin.com/in/nagenderchetti', NULL, NULL, 'Neura Vision', FALSE, '[{"name": "Neura Vision"}, {"name": "Suncorp Group"}]'::jsonb, 'uk', ARRAY['uk', 'australia'], NULL, 'nagender-chetti', 'International Founder', ARRAY['both'], TRUE, FALSE)
